// ── Thresholds ──────────────────────────────
const RAM_ALERT_PCT  = 95;   // alert if RAM usage exceeds this %
const TEMP_ALERT_C   = 85;   // alert if any thermal zone exceeds this °C
const DISK_MIN_GB    = 50;   // alert if D: free space drops below this GB
const SUSTAIN_CHECKS = 2;    // consecutive readings required for spike alerts (RAM/temp)

// Persistent counters across executions (only persists while workflow is active)
const sd = $getWorkflowStaticData('global');
sd.ramHigh  = sd.ramHigh  || 0;
sd.tempHigh = sd.tempHigh || 0;

// ── Service checks (immediate) ──────────────
const checks = [
  { name: 'Radarr',      node: 'Check Radarr' },
  { name: 'Sonarr',      node: 'Check Sonarr' },
  { name: 'Prowlarr',    node: 'Check Prowlarr' },
  { name: 'qBittorrent', node: 'Check qBittorrent' },
  { name: 'Tdarr',       node: 'Check Tdarr' },
  { name: 'Plex',        node: 'Check Plex' },
];

const downServices = checks.filter(c => {
  try {
    const d = $(c.node).first().json;
    return !d || d.statusCode >= 400 || d.error || d.code === 'ECONNREFUSED';
  } catch(e) { return true; }
}).map(c => c.name);

// ── System metric checks ─────────────────────
let ramOver = false, tempOver = false, diskLow = false;
let ramDetail = '', tempDetail = '', diskDetail = '';

try {
  const resp = $('System Metrics').first().json;
  const text = typeof resp === 'string' ? resp : (resp.data ?? resp.body ?? '');

  // RAM
  const memAvail = parseFloat((text.match(/windows_os_physical_memory_free_bytes\s+([\d.e+]+)/) || [])[1]);
  const memTotal = parseFloat((text.match(/windows_os_visible_memory_bytes\s+([\d.e+]+)/) || [])[1]);
  if (memTotal && memAvail) {
    const usedPct = Math.round((1 - memAvail / memTotal) * 100);
    if (usedPct >= RAM_ALERT_PCT) {
      ramOver = true;
      ramDetail = `RAM usage critical: ${usedPct}% used (${((memTotal - memAvail)/1e9).toFixed(1)} / ${(memTotal/1e9).toFixed(1)} GB)`;
    }
  }

  // Disk D: (immediate)
  const diskFree = parseFloat((text.match(/windows_logical_disk_free_bytes\{[^}]*volume="D:"[^}]*\}\s+([\d.e+]+)/) || [])[1]);
  if (diskFree) {
    const freeGB = diskFree / 1e9;
    if (freeGB < DISK_MIN_GB) {
      diskLow = true;
      diskDetail = `Disk D: low: ${freeGB.toFixed(0)} GB remaining`;
    }
  }

  // Temps
  const tempMatches = [...text.matchAll(/windows_thermalzone_temperature_celsius\{[^}]+\}\s+([\d.e+]+)/g)];
  for (const m of tempMatches) {
    const temp = parseFloat(m[1]);
    if (temp >= TEMP_ALERT_C) {
      tempOver = true;
      tempDetail = `High temperature: ${temp.toFixed(1)}°C`;
      break;
    }
  }
} catch(e) {
  // metrics unavailable — don't block service alerts
}

// ── Update sustain counters ──────────────────
sd.ramHigh  = ramOver  ? sd.ramHigh + 1  : 0;
sd.tempHigh = tempOver ? sd.tempHigh + 1 : 0;

// ── Assemble alerts ──────────────────────────
const alerts = [];
for (const s of downServices) alerts.push(`❌ Service down: ${s}`);
if (diskLow) alerts.push(`⚠️ ${diskDetail}`);
// Spikes: fire once when they first reach the sustained threshold (=== avoids re-spamming every 5 min)
if (sd.ramHigh  === SUSTAIN_CHECKS) alerts.push(`⚠️ ${ramDetail} (sustained ${SUSTAIN_CHECKS} checks)`);
if (sd.tempHigh === SUSTAIN_CHECKS) alerts.push(`⚠️ ${tempDetail} (sustained ${SUSTAIN_CHECKS} checks)`);

if (alerts.length === 0) return [];

return [{ json: { alerts, count: alerts.length } }];

